1603	    GGML_ASSERT(messages.is_array());
1604	    for (auto & message : messages) {
1605	        if (message.contains("tool_calls")) {
1606	            for (auto & tool_call : message["tool_calls"]) {
1607	                if (tool_call.contains("function") && tool_call["function"].contains("arguments")) {
1608	                    auto & args = tool_call["function"]["arguments"];
